import React, { useState } from 'react';

const CounterComponent = () => {
  const [count, setCount] = useState(0);
  const [step, setStep] = useState(1);

  const increase = () => {
    setCount(Math.min(count + step, 100));
  };

  const decrease = () => {
    setCount(Math.max(count - step, 0));
  };

  return (
    <div>
      <h2>Count: {count}</h2>
      <label>Step:<input type="number" value={step} onChange={(e) => setStep(Number(e.target.value))} /></label>
      <button onClick={increase}>Increase</button>
      <button onClick={decrease}>Decrease</button>
      <button onClick={() => setCount(0)}>Reset</button>
      <button onClick={() => setCount(Math.min(count + step * 2, 100))}>Double</button>
      <button onClick={() => setCount(Math.min(count + step * 3, 100))}>Triple</button>
    </div>
  );
};

const App = () => {
  return (
    <div>
      <CounterComponent />
      <CounterComponent />
    </div>
  );
};

export default App;

